const data = $input.first().json;
const call = data.body ? data.body.call : data.call;
const fromNumber = (call && call.from_number) ? call.from_number : '';
const transcript = (call && call.transcript) ? call.transcript : 'No transcript available';
const nowIso = new Date().toISOString();

return [{
  json: {
    model: 'claude-sonnet-4-20250514',
    max_tokens: 1024,
    system: 'You are a call analysis assistant. Extract caller information from business phone call transcripts. Always return valid JSON only — no markdown, no explanation, no code fences. Phone numbers must always be in E.164 format (e.g. +61400000000). Datetimes must always be in ISO 8601 format with timezone offset (e.g. 2026-04-07T09:00:00+08:00).',
    messages: [{
      role: 'user',
      content: 'Analyse this inbound business phone call. The caller incoming phone number (caller ID) is: ' + (fromNumber || 'unknown') + '. The current datetime is: ' + nowIso + '. The business operates in Australia/Perth timezone (UTC+08:00).\n\nReturn ONLY valid JSON with this exact structure:\n{"callerName":"string or Unknown","callerPhone":"E.164 phone number","callerEmail":"string or empty","intent":"why they called","appointmentRequested":true or false,"appointmentBooked":true or false,"appointmentTime":"ISO 8601 datetime with timezone offset (e.g. 2026-04-07T09:00:00+08:00) or empty string","summary":"1-2 sentence summary","actionItems":"next steps or empty string"}\n\nIMPORTANT:\n- callerPhone must NEVER be empty — if the caller did not state a phone number, use the incoming caller ID (' + (fromNumber || '+61000000000') + '). Always normalize to E.164 format.\n- If appointmentBooked is true, you MUST extract appointmentTime as a full ISO 8601 datetime in the business timezone (Australia/Perth, UTC+08:00). Use the current datetime as reference for relative dates like "tomorrow" or "Tuesday". For example, if the caller says "Tuesday at 9 am" and today is Monday April 6th, return "2026-04-07T09:00:00+08:00".\n- Set appointmentBooked to true only if the transcript shows a specific time was confirmed and booked during the call.\n\nTranscript:\n' + transcript
    }]
  }
}];

const text = $input.first().json.content[0].text.trim();
let result;
try {
  const clean = text.replace(/^```json\s*/,'').replace(/```\s*$/,'');
  result = JSON.parse(clean);
} catch {
  result = { callerName: 'Unknown', callerPhone: '', callerEmail: '', intent: 'unknown', appointmentRequested: false, appointmentBooked: false, summary: text, actionItems: '' };
}
return [{ json: result }];

const analysis = $('Parse Call Analysis').first().json;
const businessName = "{{BUSINESS_NAME}}";
const bookingLink = "{{BOOKING_LINK}}";
const name = analysis.callerName || 'there';
const email = analysis.callerEmail || '';
if (!email || !bookingLink) return [];
const html = '<div style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto;padding:20px">'
  + '<div style="background:linear-gradient(135deg,#667eea 0%,#764ba2 100%);padding:30px;border-radius:10px;text-align:center;margin-bottom:30px">'
  + '<h1 style="color:white;margin:0">Book Your Appointment</h1></div>'
  + '<p style="font-size:16px;color:#333">Hi ' + name + ',</p>'
  + '<p style="font-size:16px;color:#333">Thanks for calling <strong>' + businessName + '</strong>! As discussed, here is your link to book a time that suits you:</p>'
  + '<div style="text-align:center;margin:30px 0">'
  + '<a href="' + bookingLink + '" style="background:linear-gradient(135deg,#667eea 0%,#764ba2 100%);color:white;padding:15px 30px;text-decoration:none;border-radius:8px;font-size:16px;font-weight:bold">Book Your Appointment</a></div>'
  + '<p style="font-size:14px;color:#666">If the button does not work, copy this link: ' + bookingLink + '</p>'
  + '<p style="font-size:14px;color:#666">Looking forward to speaking with you!<br><strong>The ' + businessName + ' Team</strong></p></div>';
return [{ json: { to: email, subject: 'Book your appointment with ' + businessName, html } }];

const analysis = $('Parse Call Analysis').first().json;
const businessName = "{{BUSINESS_NAME}}";
const name = analysis.callerName || 'there';
const email = analysis.callerEmail || '';
if (!email) return [];
const summary = analysis.summary || '';
const html = '<div style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto;padding:20px">'
  + '<div style="background:linear-gradient(135deg,#667eea 0%,#764ba2 100%);padding:30px;border-radius:10px;text-align:center;margin-bottom:30px">'
  + '<h1 style="color:white;margin:0">Appointment Confirmed!</h1></div>'
  + '<p style="font-size:16px;color:#333">Hi ' + name + ',</p>'
  + '<p style="font-size:16px;color:#333">Your appointment with <strong>' + businessName + '</strong> has been confirmed. A calendar invitation has been sent to this email address.</p>'
  + '<div style="background:#f8f9fa;border-left:4px solid #667eea;padding:15px;margin:20px 0;border-radius:4px">'
  + '<p style="margin:0;color:#333;font-size:14px">' + summary + '</p></div>'
  + '<p style="font-size:14px;color:#666">If you need to reschedule or have any questions, please reply to this email or call us directly.</p>'
  + '<p style="font-size:14px;color:#666">We look forward to seeing you!<br><strong>The ' + businessName + ' Team</strong></p></div>';
return [{ json: { to: email, subject: 'Appointment confirmed with ' + businessName, html } }];

const data = $input.first().json;
const body = data.body || data;
const name = body.contactName || body.caller_name || 'there';
const email = body.contactEmail || body.caller_email || '';
const startTime = body.startTime || body.start_time || '';
const businessName = body.businessName || '{{BUSINESS_NAME}}';
const eventLink = body.eventLink || '';
if (!email) return [];
const formattedTime = startTime ? new Date(startTime).toLocaleString('en-US', { weekday: 'long', month: 'long', day: 'numeric', hour: 'numeric', minute: '2-digit' }) : 'as discussed';
const html = '<div style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto;padding:20px">'
  + '<div style="background:linear-gradient(135deg,#667eea 0%,#764ba2 100%);padding:30px;border-radius:10px;text-align:center;margin-bottom:30px">'
  + '<h1 style="color:white;margin:0">Appointment Confirmed!</h1></div>'
  + '<p style="font-size:16px;color:#333">Hi ' + name + ',</p>'
  + '<p style="font-size:16px;color:#333">Your appointment with <strong>' + businessName + '</strong> has been confirmed for <strong>' + formattedTime + '</strong>.</p>'
  + '<p style="font-size:16px;color:#333">A calendar invitation has been sent to your email.</p>'
  + (eventLink ? '<div style="text-align:center;margin:30px 0"><a href="' + eventLink + '" style="background:linear-gradient(135deg,#667eea 0%,#764ba2 100%);color:white;padding:15px 30px;text-decoration:none;border-radius:8px;font-size:16px;font-weight:bold">View Calendar Event</a></div>' : '')
  + '<p style="font-size:14px;color:#666">If you need to reschedule, please reply to this email or call us directly.</p>'
  + '<p style="font-size:14px;color:#666">We look forward to seeing you!<br><strong>The ' + businessName + ' Team</strong></p></div>';
return [{ json: { to: email, subject: 'Appointment confirmed with ' + businessName, html, contactName: name, contactEmail: email, startTime, eventLink } }];
